package ua.university.sms.controller;
import jakarta.validation.Valid;import org.springframework.http.*;import org.springframework.web.bind.annotation.*;import ua.university.sms.model.dto.EnrollmentDtos.*;import ua.university.sms.service.EnrollmentService;import java.util.*;
@RestController @RequestMapping("/api/enrollments") public class EnrollmentController{private final EnrollmentService service;public EnrollmentController(EnrollmentService service){this.service=service;}@PostMapping public ResponseEntity<Response> create(@Valid @RequestBody Request r){return ResponseEntity.status(HttpStatus.CREATED).body(service.create(r));}@GetMapping("/{id}") public Response get(@PathVariable Long id){return service.get(id);}@GetMapping public List<Response> list(){return service.list();}@PutMapping("/{id}") public Response update(@PathVariable Long id,@Valid @RequestBody Request r){return service.update(id,r);}@PatchMapping("/{id}/payment") public Response payment(@PathVariable Long id,@RequestBody PaymentRequest r){return service.setPaid(id,r);}@PatchMapping("/{id}/grade") public Response grade(@PathVariable Long id,@Valid @RequestBody GradeRequest r){return service.setGrade(id,r);}@GetMapping("/average/course/{courseId}") public Double averageCourse(@PathVariable Long courseId){return service.averageByCourse(courseId);}@GetMapping("/average/semester/{semester}") public Double averageSemester(@PathVariable String semester){return service.averageBySemester(semester);}@DeleteMapping("/{id}") @ResponseStatus(HttpStatus.NO_CONTENT) public void delete(@PathVariable Long id){service.delete(id);}}
